const orgs = $input.first().json;
if (!Array.isArray(orgs) || orgs.length === 0) return [{ json: { _skip: true } }];
return orgs.map(o => ({ json: { organization_id: o.id } }));

// Pure compute. Mirrors lib/dashboard/quick-action-suggestions.ts.
// Inputs assembled from previous 4 fetches.
const orgId = $node['Split Orgs'].json.organization_id;
const crmSuggs = ($input.all()[0]?.json) || [];
const tokens = ($input.all()[1]?.json) || [];
const drafts = ($input.all()[2]?.json) || [];
const stock = ($input.all()[3]?.json) || [];
const now = new Date();
const DAY_MS = 24*60*60*1000;
const candidates = [];

// crm.hot_leads (priority 80)
const hotLeads = (Array.isArray(crmSuggs) ? crmSuggs : []).filter(s => s.card_type === 'hot_lead' && s.score >= 3);
if (hotLeads.length > 0) {
  candidates.push({
    type: 'crm.hot_leads',
    priority: 80,
    headline: `${hotLeads.length} hot lead${hotLeads.length===1?'':'s'} need follow-up`,
    body: 'Your CRM flagged high-value deals with recent contact. Review and approve follow-ups.',
    cta_label: 'Open CRM',
    cta_href: '/crm',
    metadata: { count: hotLeads.length, top_score: Math.max(...hotLeads.map(h=>h.score)) }
  });
}

// crm.followups (priority 50)
const followups = (Array.isArray(crmSuggs) ? crmSuggs : []).filter(s => s.card_type === 'followup' && s.score >= 3);
if (followups.length > 0) {
  candidates.push({
    type: 'crm.followups',
    priority: 50,
    headline: `${followups.length} contact${followups.length===1?'':'s'} flagged for follow-up`,
    body: 'AI-curated follow-ups based on engagement patterns. One-click approve in CRM Easy view.',
    cta_label: 'Review follow-ups',
    cta_href: '/crm',
    metadata: { count: followups.length }
  });
}

// token.expiring (priority 100)
const expiringSoon = (Array.isArray(tokens) ? tokens : []).filter(t => {
  if (!t.expires_at) return false;
  const days = (new Date(t.expires_at).getTime() - now.getTime()) / DAY_MS;
  return days >= 0 && days <= 3;
});
if (expiringSoon.length > 0) {
  candidates.push({
    type: 'token.expiring',
    priority: 100,
    headline: `Reconnect ${expiringSoon[0].provider} — expires soon`,
    body: 'OAuth tokens are about to expire. Reconnect to keep automations running.',
    cta_label: 'Open integrations',
    cta_href: '/settings/integrations',
    metadata: { providers: expiringSoon.map(t=>t.provider) }
  });
}

// campaigns.draft_pending (priority 70)
const pendingDrafts = (Array.isArray(drafts) ? drafts : []).filter(d => d.status === 'pending_approval');
if (pendingDrafts.length > 0) {
  candidates.push({
    type: 'campaigns.draft_pending',
    priority: 70,
    headline: `${pendingDrafts.length} campaign draft${pendingDrafts.length===1?'':'s'} awaiting approval`,
    body: 'Brand-safety review complete. Approve to schedule the send.',
    cta_label: 'Review drafts',
    cta_href: '/campaigns',
    metadata: { count: pendingDrafts.length }
  });
}

// accommodation.low_stock (priority 60)
const lowStock = (Array.isArray(stock) ? stock : []).filter(s => s.quantity <= s.threshold);
if (lowStock.length > 0) {
  candidates.push({
    type: 'accommodation.low_stock',
    priority: 60,
    headline: `${lowStock.length} accommodation stock item${lowStock.length===1?'':'s'} below threshold`,
    body: 'Restock alert from nightly inventory check. Review and reorder.',
    cta_label: 'Open stock',
    cta_href: '/accommodation/stock',
    metadata: { items: lowStock.map(s=>s.item) }
  });
}

if (candidates.length === 0) return [{ json: { _skip: true, organization_id: orgId } }];

// Pick top by priority
candidates.sort((a,b) => b.priority - a.priority);
const top = candidates[0];

return [{ json: {
  organization_id: orgId,
  action_type: top.type,
  priority: top.priority,
  headline: top.headline,
  body: top.body,
  cta_label: top.cta_label,
  cta_href: top.cta_href,
  metadata: top.metadata,
  refreshed_at: now.toISOString()
}}];
